"""
TDD Stage: full_normalize
Full layer_norm: Pass 3 does (x-mean)*rsqrt(var+eps)*gamma+beta
"""

import pytest
import torch
import ttnn


from .layer_norm import layer_norm


def pytorch_reference(x, gamma, beta):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(
        x.float(), [x.shape[-1]], weight=gamma.float(), bias=beta.float(), eps=1e-5
    ).to(x.dtype)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
        pytest.param((1, 1, 32, 512), id="1x1x32x512"),
    ],
)
def test_full_normalize(device, shape):
    """Verify Full layer_norm: Pass 3 does (x-mean)*rsqrt(var+eps)*gamma+beta."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma = torch.randn(shape[-1])
    beta = torch.randn(shape[-1])

    expected = pytorch_reference(torch_input, gamma, beta)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tt = ttnn.from_torch(
        gamma.unsqueeze(0).unsqueeze(0).unsqueeze(0),
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
    )
    beta_tt = ttnn.from_torch(
        beta.unsqueeze(0).unsqueeze(0).unsqueeze(0),
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
    )

    ttnn_output = layer_norm(ttnn_input, gamma_tt, beta_tt)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
